// src/pages/donor/DonatePage.jsx
import { useState } from "react";
import { useToast } from "../../context/ToastContext";
import PageHeader   from "../../components/shared/PageHeader";
import Badge        from "../../components/shared/Badge";
import { funds }    from "../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";
const openFunds = funds.filter((f) => f.status === "open");

export default function DonatePage() {
  const toast = useToast();
  const [selected, setSelected] = useState(null);
  const [amount,   setAmount]   = useState("");

  const handleDonate = () => {
    if (selected && amount) {
      toast(`Donation of ${amount} tokens submitted!`, "success");
      setAmount("");
      setSelected(null);
    } else {
      toast("Select a fund and enter an amount", "error");
    }
  };

  return (
    <div>
      <PageHeader title="Make a Donation" desc="Support a cause by donating tokens to an open fund" />
      <div className="grid-2">
        {/* Fund selector */}
        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Select Fund</div>
          <div className="section-gap">
            {openFunds.map((f) => {
              const pct = Math.round((f.raised / f.target) * 100);
              return (
                <div
                  key={f.id}
                  onClick={() => setSelected(f.id)}
                  style={{ padding:14, borderRadius:"var(--radius)", border:`1px solid ${selected===f.id?"rgba(212,168,67,.5)":"var(--border)"}`, background: selected===f.id ? "var(--gold-glow)" : "var(--bg-surface)", cursor:"pointer", transition:"all .15s" }}
                >
                  <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6, flexWrap:"wrap", gap:4 }}>
                    <span style={{ fontWeight:700, fontSize:13 }}>{f.name}</span>
                    <Badge type="teal">{f.id}</Badge>
                  </div>
                  <div style={{ fontSize:12, color:"var(--text-3)", marginBottom:8 }}>
                    {fmt(f.raised)} / {fmt(f.target)} tokens · {f.donors} donors
                  </div>
                  <div className="progress-track"><div className="progress-fill" style={{ width:`${pct}%` }} /></div>
                  <div style={{ fontSize:11, color:"var(--gold)", marginTop:4, fontFamily:"'DM Mono',monospace" }}>{pct}% funded</div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Donation form */}
        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Donation Details</div>
          <div className="form-grid section-gap">
            <div className="stat-card gold">
              <div className="stat-label">Your Token Balance</div>
              <div className="stat-value gold">2,400</div>
            </div>
            <div className="form-group">
              <label>Selected Fund</label>
              <input readOnly value={selected ? funds.find((f) => f.id === selected)?.name || "" : ""} placeholder="Select a fund from the list..." />
            </div>
            <div className="form-group">
              <label>Amount (Tokens)</label>
              <input value={amount} onChange={(e) => setAmount(e.target.value)} type="number" placeholder="e.g. 100" />
              <span className="input-hint">Min: 10 · Max: 2,400</span>
            </div>
            <div className="form-actions">
              <button className="btn btn-primary full-width" style={{ justifyContent:"center" }} onClick={handleDonate}>
                ♡ Donate Now
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
